import{_ as a,o as n,c as e,ag as t}from"./chunks/framework.BYehg5q7.js";const u=JSON.parse('{"title":"Context Assembly","description":"","frontmatter":{},"headers":[],"relativePath":"contributor/context-assembly.md","filePath":"contributor/context-assembly.md","lastUpdated":1774954986000}'),p={name:"contributor/context-assembly.md"};function o(l,s,i,r,c,d){return n(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="context-assembly" tabindex="-1">Context Assembly <a class="header-anchor" href="#context-assembly" aria-label="Permalink to &quot;Context Assembly&quot;">​</a></h1><p>How user-provided data becomes AI prompts. This is the core intelligence layer — every AI feature is only as good as the context it receives.</p><h2 id="the-big-picture" tabindex="-1">The Big Picture <a class="header-anchor" href="#the-big-picture" aria-label="Permalink to &quot;The Big Picture&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                           ┌─────────────────────────────────────────┐</span></span>
<span class="line"><span>                           │           7 AI FEATURES                 │</span></span>
<span class="line"><span>                           │                                         │</span></span>
<span class="line"><span>                           │  Chat  Focus  Health  PDF   Persona     │</span></span>
<span class="line"><span>                           │  Panel Card   Dots    Import Generator  │</span></span>
<span class="line"><span>                           │  Per-Marker AI   Correlation AI         │</span></span>
<span class="line"><span>                           └────────────┬────────────────────────────┘</span></span>
<span class="line"><span>                                        │</span></span>
<span class="line"><span>                                        ▼</span></span>
<span class="line"><span>                              ┌──────────────────┐</span></span>
<span class="line"><span>                              │  callClaudeAPI() │  ← single entry point</span></span>
<span class="line"><span>                              │     api.js       │</span></span>
<span class="line"><span>                              └────────┬─────────┘</span></span>
<span class="line"><span>                                       │</span></span>
<span class="line"><span>                    ┌──────────┬───────┴────────┬──────────┐</span></span>
<span class="line"><span>                    ▼          ▼                ▼          ▼</span></span>
<span class="line"><span>               Anthropic   OpenRouter       Venice     Local AI</span></span>
<span class="line"><span>               Messages    (OpenAI-compat)  (OpenAI)   (OpenAI-compat)</span></span>
<span class="line"><span>               API + SSE   via shared       via shared  via shared</span></span>
<span class="line"><span>                           helper           helper      helper</span></span></code></pre></div><p>Every AI call passes the same shape: <code>{ system, messages, maxTokens, onStream? }</code>. The caller assembles the prompt; the router just delivers it.</p><h2 id="data-sources" tabindex="-1">Data Sources <a class="header-anchor" href="#data-sources" aria-label="Permalink to &quot;Data Sources&quot;">​</a></h2><p>Everything the AI can know about the user comes from these sources:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                        USER DATA SOURCES                            │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                                                                     │</span></span>
<span class="line"><span>│  PROFILE                    CONTEXT CARDS (9)      LAB DATA         │</span></span>
<span class="line"><span>│  ├─ sex                     ├─ Health Goals         ├─ entries[]    │</span></span>
<span class="line"><span>│  ├─ DOB (→ age)             ├─ Medical Conditions   ├─ dates[]      │</span></span>
<span class="line"><span>│  └─ location/latitude       ├─ Diet                 ├─ marker values│</span></span>
<span class="line"><span>│                             ├─ Exercise             ├─ ref ranges   │</span></span>
<span class="line"><span>│  PERSONA                    ├─ Sleep &amp; Rest         ├─ optimal ranges│</span></span>
<span class="line"><span>│  ├─ personality ID          ├─ Light &amp; Circadian    ├─ phase ranges │</span></span>
<span class="line"><span>│  ├─ promptText              ├─ Stress               ├─ custom markers│</span></span>
<span class="line"><span>│  └─ evidenceBased flag      ├─ Love Life            └─ flagged results│</span></span>
<span class="line"><span>│                             └─ Environment                          │</span></span>
<span class="line"><span>│  CHAT                                                               │</span></span>
<span class="line"><span>│  ├─ user message            OTHER                                   │</span></span>
<span class="line"><span>│  └─ last 10 history msgs    ├─ Interpretive Lens                   │</span></span>
<span class="line"><span>│                             ├─ Context Notes                        │</span></span>
<span class="line"><span>│  MARKER SCHEMA              ├─ Menstrual Cycle                      │</span></span>
<span class="line"><span>│  ├─ MARKER_SCHEMA           ├─ Supplements                          │</span></span>
<span class="line"><span>│  └─ customMarkers           ├─ User Notes                           │</span></span>
<span class="line"><span>│                             └─ Genetics (SNPs, if imported)         │</span></span>
<span class="line"><span>│                                                                     │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><h2 id="buildlabcontext-—-the-central-serializer" tabindex="-1">buildLabContext() — The Central Serializer <a class="header-anchor" href="#buildlabcontext-—-the-central-serializer" aria-label="Permalink to &quot;buildLabContext() — The Central Serializer&quot;">​</a></h2><p><code>buildLabContext()</code> in <code>chat.js</code> is the single function that converts all user data into a plain-text block. It is used by Chat and Health Dots. The Focus Card uses the lighter <code>buildFocusContext()</code> instead.</p><h3 id="output-structure" tabindex="-1">Output Structure <a class="header-anchor" href="#output-structure" aria-label="Permalink to &quot;Output Structure&quot;">​</a></h3><p>Sections are ordered by priority — the AI sees &quot;what are you trying to solve?&quot; first, then &quot;what do the numbers say?&quot;, then medical/lifestyle context. This exploits primacy bias in LLMs.</p><p>Each section is wrapped in <code>[section:name]...[/section:name]</code> tags for machine-parsable extraction (used by getbased-mcp, Hermes Agent, OpenClaw). Flagged results use <code>[critical]...[/critical]</code>. Lab sections include an <code>updated:date</code> attribute.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Lab data for current profile (sex: female, age: 34, unit system: SI, today: 2026-02-24,</span></span>
<span class="line"><span>  dates: Jan 15, Feb 20, Mar 10):</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[section:healthGoals]                      ←── 1. GOALS (what to optimize)</span></span>
<span class="line"><span>## Health Goals (Things to Solve)</span></span>
<span class="line"><span>### Major Priority</span></span>
<span class="line"><span>- Optimize thyroid function</span></span>
<span class="line"><span>### Mild Priority</span></span>
<span class="line"><span>- Improve sleep quality</span></span>
<span class="line"><span>[/section:healthGoals]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[section:interpretiveLens]                 ←── 2. LENS (analytical framework)</span></span>
<span class="line"><span>## Interpretive Lens</span></span>
<span class="line"><span>Quantum biology, functional medicine paradigm</span></span>
<span class="line"><span>[/section:interpretiveLens]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[index]                                    ←── category index for selective parsing</span></span>
<span class="line"><span>Available sections: biochemistry, hormones, lipidPanel</span></span>
<span class="line"><span>[/index]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Note: status labels below use reference ranges.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[section:biochemistry updated:2026-03-10]  ←── 3. LAB VALUES (the data)</span></span>
<span class="line"><span>## Biochemistry</span></span>
<span class="line"><span>- Glucose: Jan 15: 5.2, Feb 20: 5.0, Mar 10: 4.9 mmol/L (ref: 3.9–5.6, status: normal)</span></span>
<span class="line"><span>- Creatinine: Jan 15: 72, Feb 20: 70 µmol/L (ref: 53–97, status: normal)</span></span>
<span class="line"><span>[/section:biochemistry]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[section:hormones updated:2026-02-20]</span></span>
<span class="line"><span>## Hormones</span></span>
<span class="line"><span>- Estradiol: Jan 15: 180 [follicular, ref 77–921], Feb 20: 95 [luteal, ref 65–380] pmol/L</span></span>
<span class="line"><span>  ↑ phase-aware: each value shows its cycle phase + phase-specific ref range</span></span>
<span class="line"><span>[/section:hormones]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[critical]                                 ←── 4. FLAGS (quick-scan summary)</span></span>
<span class="line"><span>## Flagged Results (Latest)</span></span>
<span class="line"><span>- Ferritin: 12 µg/L (LOW, range: 15–200)</span></span>
<span class="line"><span>[/critical]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[section:userNotes]                        ←── 5. NOTES (temporal context)</span></span>
<span class="line"><span>## User Notes</span></span>
<span class="line"><span>- Jan 10: Started new thyroid medication</span></span>
<span class="line"><span>- Feb 15: Feeling much better energy-wise</span></span>
<span class="line"><span>[/section:userNotes]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[section:diagnoses]                        ←── 6. MEDICAL CONTEXT</span></span>
<span class="line"><span>## Medical Conditions / Diagnoses</span></span>
<span class="line"><span>- Hashimoto&#39;s (major, since 2020)</span></span>
<span class="line"><span>Notes: On levothyroxine 50mcg</span></span>
<span class="line"><span>[/section:diagnoses]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[section:supplements]                      ←── 7. SUPPLEMENTS</span></span>
<span class="line"><span>## Supplements &amp; Medications</span></span>
<span class="line"><span>- Vitamin D3 (5000 IU) [supplement]: Jan 1 → ongoing</span></span>
<span class="line"><span>- Magnesium glycinate (400mg) [supplement]: Jan 15 → ongoing</span></span>
<span class="line"><span>[/section:supplements]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[section:menstrualCycle]                   ←── 8. CYCLE (female only)</span></span>
<span class="line"><span>## Menstrual Cycle</span></span>
<span class="line"><span>Profile: 28-day cycle (5-day period), regular, moderate flow.</span></span>
<span class="line"><span>Recent periods: Jan 3-Jan 7 (moderate) [Cramps, Fatigue], ...</span></span>
<span class="line"><span>Blood draw cycle context:</span></span>
<span class="line"><span>- Jan 15: Day 13 (follicular phase)</span></span>
<span class="line"><span>- Feb 20: Day 18 (luteal phase)</span></span>
<span class="line"><span>Next optimal blood draw window: Mar 3-5</span></span>
<span class="line"><span>[/section:menstrualCycle]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[section:diet]                             ←── 9-15. LIFESTYLE CARDS</span></span>
<span class="line"><span>## Diet &amp; Digestion</span></span>
<span class="line"><span>Type: Mediterranean. Pattern: 3 meals.</span></span>
<span class="line"><span>Breakfast (07:00): eggs, avocado</span></span>
<span class="line"><span>Lunch (12:30): salad with chicken</span></span>
<span class="line"><span>Dinner (19:00): salmon, vegetables</span></span>
<span class="line"><span>[/section:diet]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Exercise &amp; Movement</span></span>
<span class="line"><span>Frequency: 4x/week. Types: weights, yoga. Intensity: moderate.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Sleep &amp; Rest</span></span>
<span class="line"><span>Duration: 7-8h. Quality: good. Room temp: 65°F.</span></span>
<span class="line"><span>Environment: blackout curtains, grounding sheet.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Light &amp; Circadian</span></span>
<span class="line"><span>Morning light: 15min. UV exposure: moderate. Latitude: 40-50°N.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Stress</span></span>
<span class="line"><span>Level: moderate. Sources: work, finances.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Love Life &amp; Sexual Health</span></span>
<span class="line"><span>Status: partnered. Relationship quality: good. Libido: normal.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Environment</span></span>
<span class="line"><span>Water: filtered. EMF: wifi router. Home lighting: mixed.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Context Change Timeline                 ←── 17. CHANGE HISTORY</span></span>
<span class="line"><span>- Mar 1, 2026: Diet &amp; Digestion — type: omnivore → carnivore</span></span>
<span class="line"><span>- Feb 15, 2026: Stress — level: high → moderate</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Additional Context Notes                ←── 18. FREETEXT NOTES</span></span>
<span class="line"><span>Started cold plunges in January</span></span></code></pre></div><h3 id="empty-card-guards" tabindex="-1">Empty-Card Guards <a class="header-anchor" href="#empty-card-guards" aria-label="Permalink to &quot;Empty-Card Guards&quot;">​</a></h3><p>Cards with no meaningful content are omitted entirely (not sent as empty sections). Each card checks for actual data:</p><ul><li><code>diagnoses</code>: conditions array not empty OR note has text</li><li><code>diet</code>: type set OR any meal content OR note</li><li><code>exercise</code>: frequency set OR types array not empty OR note</li><li><code>sleepRest</code>: duration set OR quality set OR issues not empty OR note</li><li><code>stress</code>: level set OR sources not empty OR note</li><li><code>loveLife</code>: status set OR libido set OR concerns not empty OR note</li><li><code>environment</code>: setting set OR water set OR air not empty OR note</li></ul><h3 id="data-flow-diagram" tabindex="-1">Data Flow Diagram <a class="header-anchor" href="#data-flow-diagram" aria-label="Permalink to &quot;Data Flow Diagram&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>importedData (localStorage)</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ├─── .healthGoals ────────────────────────────────┐  ← FIRST</span></span>
<span class="line"><span>         ├─── .interpretiveLens ───────────────────────────┤</span></span>
<span class="line"><span>         │                                                 │</span></span>
<span class="line"><span>         └─── .entries ──┐                                 │</span></span>
<span class="line"><span>                         ▼                                 │</span></span>
<span class="line"><span>                  getActiveData()                          │</span></span>
<span class="line"><span>                    │                                      │</span></span>
<span class="line"><span>                    ├─── categories[].markers[]             │</span></span>
<span class="line"><span>                    │     ├─ values[] (per date)            │</span></span>
<span class="line"><span>                    │     ├─ refMin/refMax                  │</span></span>
<span class="line"><span>                    │     ├─ phaseRefRanges[] (female)      │</span></span>
<span class="line"><span>                    │     └─ phaseLabels[] (female)         │</span></span>
<span class="line"><span>                    │                                      │</span></span>
<span class="line"><span>                    └─── getAllFlaggedMarkers() ────────────┤</span></span>
<span class="line"><span>                                                           │</span></span>
<span class="line"><span>         ├─── .notes ──────────────────────────────────────┤</span></span>
<span class="line"><span>         ├─── .diagnoses ──────────────────────────────────┤</span></span>
<span class="line"><span>         ├─── .supplements ────────────────────────────────┤  ← MEDICAL</span></span>
<span class="line"><span>         ├─── .menstrualCycle ─── + helper functions ──────┤</span></span>
<span class="line"><span>         │     ├─ getCyclePhase()                          │</span></span>
<span class="line"><span>         │     ├─ getBloodDrawPhases()                     │</span></span>
<span class="line"><span>         │     ├─ getNextBestDrawDate()                    │</span></span>
<span class="line"><span>         │     ├─ detectPerimenopausePattern()             │</span></span>
<span class="line"><span>         │     └─ detectCycleIronAlerts()                  │</span></span>
<span class="line"><span>         ├─── .diet ───────────────────────────────────────┤</span></span>
<span class="line"><span>         ├─── .exercise ───────────────────────────────────┤</span></span>
<span class="line"><span>         ├─── .sleepRest ──────────────────────────────────┤  ← LIFESTYLE</span></span>
<span class="line"><span>         ├─── .lightCircadian ─── + getLatitudeFromLocation()</span></span>
<span class="line"><span>         ├─── .stress ─────────────────────────────────────┤</span></span>
<span class="line"><span>         ├─── .loveLife ───────────────────────────────────┤</span></span>
<span class="line"><span>         ├─── .environment ────────────────────────────────┤</span></span>
<span class="line"><span>         ├─── .changeHistory ──────────────────────────────┤</span></span>
<span class="line"><span>         └─── .contextNotes ───────────────────────────────┤  ← LAST</span></span>
<span class="line"><span>                                                           │</span></span>
<span class="line"><span>                                                           ▼</span></span>
<span class="line"><span>                                                  buildLabContext()</span></span>
<span class="line"><span>                                                       │</span></span>
<span class="line"><span>                                                       ▼</span></span>
<span class="line"><span>                                                  plain text block</span></span></code></pre></div><h2 id="prompt-composition-per-feature" tabindex="-1">Prompt Composition Per Feature <a class="header-anchor" href="#prompt-composition-per-feature" aria-label="Permalink to &quot;Prompt Composition Per Feature&quot;">​</a></h2><h3 id="_1-chat-panel-sendchatmessage" tabindex="-1">1. Chat Panel (<code>sendChatMessage</code>) <a class="header-anchor" href="#_1-chat-panel-sendchatmessage" aria-label="Permalink to &quot;1. Chat Panel (\`sendChatMessage\`)&quot;">​</a></h3><p>The most complex composition — layers 4 components. Lab context is placed before personality so the AI processes data first, then adopts the persona:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                    SYSTEM PROMPT                      │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  ┌────────────────────────────────────────────────┐  │</span></span>
<span class="line"><span>│  │ CHAT_SYSTEM_PROMPT (constants.js)              │  │</span></span>
<span class="line"><span>│  │ Priority-tiered structure:                     │  │</span></span>
<span class="line"><span>│  │                                                │  │</span></span>
<span class="line"><span>│  │ ## Core Rules                                  │  │</span></span>
<span class="line"><span>│  │  • NOT a doctor disclaimer                     │  │</span></span>
<span class="line"><span>│  │  • Reference specific values/dates             │  │</span></span>
<span class="line"><span>│  │  • Format with markdown                        │  │</span></span>
<span class="line"><span>│  │                                                │  │</span></span>
<span class="line"><span>│  │ ## Priority Context (apply when present)       │  │</span></span>
<span class="line"><span>│  │  • Health goals → prioritize by severity       │  │</span></span>
<span class="line"><span>│  │  • Interpretive lens → frame through experts   │  │</span></span>
<span class="line"><span>│  │  • Medical conditions → interpret accordingly  │  │</span></span>
<span class="line"><span>│  │  • Supplements → correlate start/stop dates    │  │</span></span>
<span class="line"><span>│  │  • Menstrual cycle → phase-aware hormones      │  │</span></span>
<span class="line"><span>│  │  • Notes → medication changes, symptoms        │  │</span></span>
<span class="line"><span>│  │                                                │  │</span></span>
<span class="line"><span>│  │ ## Lifestyle Context (apply when present)      │  │</span></span>
<span class="line"><span>│  │  • Diet, exercise, sleep, light, stress,       │  │</span></span>
<span class="line"><span>│  │    relationships, environment                  │  │</span></span>
<span class="line"><span>│  │  • Cross-cutting: cortisol/HPA axis note       │  │</span></span>
<span class="line"><span>│  │                                                │  │</span></span>
<span class="line"><span>│  │ ## Style                                       │  │</span></span>
<span class="line"><span>│  │  • Accessible, concise, redirect off-topic     │  │</span></span>
<span class="line"><span>│  └────────────────────────────────────────────────┘  │</span></span>
<span class="line"><span>│                       +                              │</span></span>
<span class="line"><span>│  ┌────────────────────────────────────────────────┐  │</span></span>
<span class="line"><span>│  │ &quot;Current lab data:\\n&quot;                          │  │</span></span>
<span class="line"><span>│  │ buildLabContext()  ← entire serialized context │  │</span></span>
<span class="line"><span>│  └────────────────────────────────────────────────┘  │</span></span>
<span class="line"><span>│                       +                              │</span></span>
<span class="line"><span>│  ┌────────────────────────────────────────────────┐  │</span></span>
<span class="line"><span>│  │ PERSONALITY LAYER (after data)                 │  │</span></span>
<span class="line"><span>│  │  • Default: (nothing added)                    │  │</span></span>
<span class="line"><span>│  │  • Dr. House: personality.promptAddition       │  │</span></span>
<span class="line"><span>│  │  • Custom: &quot;Persona: {promptText}&quot;             │  │</span></span>
<span class="line"><span>│  │    + evidence-based disclaimer if opted in     │  │</span></span>
<span class="line"><span>│  └────────────────────────────────────────────────┘  │</span></span>
<span class="line"><span>│                       +                              │</span></span>
<span class="line"><span>├──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                    MESSAGES                           │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  Last 10 chat history entries (role + content)       │</span></span>
<span class="line"><span>│  + current user message                              │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>├──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  maxTokens: 4096  │  streaming: yes                  │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────┘</span></span></code></pre></div><h3 id="_2-focus-card-loadfocuscard" tabindex="-1">2. Focus Card (<code>loadFocusCard</code>) <a class="header-anchor" href="#_2-focus-card-loadfocuscard" aria-label="Permalink to &quot;2. Focus Card (\`loadFocusCard\`)&quot;">​</a></h3><p>Uses the lightweight <code>buildFocusContext()</code> (~200-400 tokens) instead of full <code>buildLabContext()</code> (~2000-8000 tokens). Health-goals-aware system prompt:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  SYSTEM (if health goals exist):                     │</span></span>
<span class="line"><span>│  &quot;You are a blood work analyst. Respond with ONE     │</span></span>
<span class="line"><span>│   sentence, max 40 words. If the patient has health  │</span></span>
<span class="line"><span>│   goals listed, connect your finding to their most   │</span></span>
<span class="line"><span>│   relevant goal. Name the single most actionable     │</span></span>
<span class="line"><span>│   marker finding, its direction, and why it matters. │</span></span>
<span class="line"><span>│   No preamble, no disclaimer.&quot;                       │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  SYSTEM (no health goals):                           │</span></span>
<span class="line"><span>│  &quot;...Name the single most important marker finding,  │</span></span>
<span class="line"><span>│   its direction (rising/falling/high/low), and       │</span></span>
<span class="line"><span>│   briefly why it matters clinically...&quot;              │</span></span>
<span class="line"><span>├──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  USER: buildFocusContext()                           │</span></span>
<span class="line"><span>│    • Profile: sex, age, today                        │</span></span>
<span class="line"><span>│    • Major health goals (if any)                     │</span></span>
<span class="line"><span>│    • Flagged markers (latest values + ranges)        │</span></span>
<span class="line"><span>│    • Notable changes &gt;20% from previous              │</span></span>
<span class="line"><span>│    ~200-400 tokens total                             │</span></span>
<span class="line"><span>├──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  maxTokens: 100  │  streaming: no                     │</span></span>
<span class="line"><span>├──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  CACHE: fingerprint = hash(entries + sex + DOB +      │</span></span>
<span class="line"><span>│         all 9 cards + lens + notes + cycle + supps)   │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────┘</span></span></code></pre></div><h3 id="_3-context-card-health-dots-loadcontexthealthdots" tabindex="-1">3. Context Card Health Dots (<code>loadContextHealthDots</code>) <a class="header-anchor" href="#_3-context-card-health-dots-loadcontexthealthdots" aria-label="Permalink to &quot;3. Context Card Health Dots (\`loadContextHealthDots\`)&quot;">​</a></h3><p>Requests structured JSON for only the stale (changed) cards. JSON.parse is wrapped in try-catch — on malformed AI responses, stale cards get gray dots while cached good data is preserved:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  SYSTEM: &quot;Based on this person&#39;s lab data and        │</span></span>
<span class="line"><span>│  profile context, assess each profile area.           │</span></span>
<span class="line"><span>│  Return ONLY valid JSON with these keys...&quot;           │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  { &quot;diet&quot;: {&quot;dot&quot;:&quot;...&quot;,&quot;tip&quot;:&quot;...&quot;},                │</span></span>
<span class="line"><span>│    &quot;stress&quot;: {&quot;dot&quot;:&quot;...&quot;,&quot;tip&quot;:&quot;...&quot;} }    ← only   │</span></span>
<span class="line"><span>│                                               stale  │</span></span>
<span class="line"><span>│  Dot: green/yellow/red/gray                  cards   │</span></span>
<span class="line"><span>│  Tip: max 12 words, reference specific markers       │</span></span>
<span class="line"><span>├──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  USER: buildLabContext()                              │</span></span>
<span class="line"><span>├──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  maxTokens: 500  │  streaming: no                     │</span></span>
<span class="line"><span>├──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  CACHE: per-card fingerprint via getCardFingerprint() │</span></span>
<span class="line"><span>│         only stale cards re-fetched                   │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────┘</span></span></code></pre></div><h3 id="_4-pdf-import-parselabpdfwithai" tabindex="-1">4. PDF Import (<code>parseLabPDFWithAI</code>) <a class="header-anchor" href="#_4-pdf-import-parselabpdfwithai" aria-label="Permalink to &quot;4. PDF Import (\`parseLabPDFWithAI\`)&quot;">​</a></h3><p>Completely different context — no user profile, just schema + raw PDF. Filename is included in the user message for multi-file disambiguation:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  SYSTEM: &quot;You are a lab report data extraction       │</span></span>
<span class="line"><span>│  assistant...&quot;                                        │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  + JSON.stringify(buildMarkerReference())             │</span></span>
<span class="line"><span>│    { &quot;biochemistry.glucose&quot;: { name, unit, ref },    │</span></span>
<span class="line"><span>│      &quot;hormones.testosterone&quot;: { ... },               │</span></span>
<span class="line"><span>│      ... all known + custom markers }                 │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  + extraction rules (date format, value parsing,     │</span></span>
<span class="line"><span>│    WBC differential, custom marker suggestions)       │</span></span>
<span class="line"><span>│    WBC rule at position 3 (most error-prone)         │</span></span>
<span class="line"><span>│                                                      │</span></span>
<span class="line"><span>│  + expected JSON output schema                        │</span></span>
<span class="line"><span>├──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  USER: &quot;Extract all biomarker results from this      │</span></span>
<span class="line"><span>│  lab report (file: report.pdf):\\n\\n&quot; + pdfText       │</span></span>
<span class="line"><span>├──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  maxTokens: 8192  │  streaming: no                   │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────┘</span></span></code></pre></div><h3 id="_5-persona-generator-generatecustompersonality" tabindex="-1">5. Persona Generator (<code>generateCustomPersonality</code>) <a class="header-anchor" href="#_5-persona-generator-generatecustompersonality" aria-label="Permalink to &quot;5. Persona Generator (\`generateCustomPersonality\`)&quot;">​</a></h3><p>Standalone creative prompt — no lab data involved:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  SYSTEM: &quot;You are a persona designer for getbased.  │</span></span>
<span class="line"><span>│  Create a thorough persona covering:&quot;                 │</span></span>
<span class="line"><span>│    1. Identity &amp; Background                           │</span></span>
<span class="line"><span>│    2. Communication Style                             │</span></span>
<span class="line"><span>│    3. Medical &amp; Health Philosophy                     │</span></span>
<span class="line"><span>│    4. Analytical Approach                             │</span></span>
<span class="line"><span>│    5. Lifestyle &amp; Optimization Lens                   │</span></span>
<span class="line"><span>│    6. Character &amp; Personality                         │</span></span>
<span class="line"><span>│    7. Signature Recommendations                       │</span></span>
<span class="line"><span>│  &quot;400-500 words. No disclaimers.&quot;                     │</span></span>
<span class="line"><span>├──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  USER: &quot;Create a comprehensive persona for: {name}&quot;  │</span></span>
<span class="line"><span>├──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  maxTokens: 2048  │  streaming: yes (into textarea)  │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────┘</span></span></code></pre></div><h3 id="_6-per-marker-ai-askaiaboutmarker" tabindex="-1">6. Per-Marker AI (<code>askAIAboutMarker</code>) <a class="header-anchor" href="#_6-per-marker-ai-askaiaboutmarker" aria-label="Permalink to &quot;6. Per-Marker AI (\`askAIAboutMarker\`)&quot;">​</a></h3><p>Not a separate API call — builds a user message and injects it into the chat panel. Uses effective (phase-aware) reference ranges and includes trend direction when 2+ values exist:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>askAIAboutMarker(&quot;hormones.estradiol&quot;)</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>  &quot;Tell me about my Estradiol results.</span></span>
<span class="line"><span>   Values: Jan 15: 180 pmol/L (follicular phase, ref 77–921),</span></span>
<span class="line"><span>           Feb 20: 95 pmol/L (luteal phase, ref 65–380).</span></span>
<span class="line"><span>   Reference range: 77–921 pmol/L. Optimal range: 200–400.</span></span>
<span class="line"><span>   Current status: normal.</span></span>
<span class="line"><span>   Trend: down 47.2% from previous.</span></span>
<span class="line"><span>   Note: reference ranges shown are phase-specific.</span></span>
<span class="line"><span>   What does this mean and should I be concerned?&quot;</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>  openChatPanel(prompt) → sendChatMessage() → full Chat composition</span></span></code></pre></div><h2 id="caching-strategy" tabindex="-1">Caching Strategy <a class="header-anchor" href="#caching-strategy" aria-label="Permalink to &quot;Caching Strategy&quot;">​</a></h2><p>Each AI feature has independent caching to avoid redundant API calls:</p><table tabindex="0"><thead><tr><th>Feature</th><th>Cache Key</th><th>Fingerprint Inputs</th><th>Invalidation</th></tr></thead><tbody><tr><td>Focus Card</td><td><code>labcharts-{profile}-focusCard</code></td><td>entries + sex + DOB + 9 cards + lens + notes + cycle + supps</td><td>Any data change</td></tr><tr><td>Health Dots</td><td><code>labcharts-{profile}-contextHealth</code></td><td>Per-card: lab data + card data + sex + DOB</td><td>Only changed cards re-fetched</td></tr><tr><td>Chat</td><td><code>labcharts-{profile}-chat-t_{id}</code></td><td>N/A (conversation history)</td><td>Never invalidated, 50-thread cap</td></tr><tr><td>PDF Import</td><td>N/A</td><td>N/A</td><td>No caching</td></tr><tr><td>Persona</td><td>N/A</td><td>N/A</td><td>No caching (user saves manually)</td></tr></tbody></table><h2 id="token-budget" tabindex="-1">Token Budget <a class="header-anchor" href="#token-budget" aria-label="Permalink to &quot;Token Budget&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>maxTokens</th><th>Typical Context Size</th></tr></thead><tbody><tr><td>Chat</td><td>4096</td><td>~2,000–8,000 tokens (scales with data)</td></tr><tr><td>Focus Card</td><td>100</td><td>~200–400 tokens (lightweight context)</td></tr><tr><td>Health Dots</td><td>500</td><td>~2,000–8,000 tokens (full context)</td></tr><tr><td>PDF Import</td><td>8192</td><td>~1,000–3,000 tokens (marker schema)</td></tr><tr><td>Persona Generator</td><td>2048</td><td>~400 tokens (fixed)</td></tr></tbody></table><h2 id="key-design-decisions" tabindex="-1">Key Design Decisions <a class="header-anchor" href="#key-design-decisions" aria-label="Permalink to &quot;Key Design Decisions&quot;">​</a></h2><ol><li><p><strong>Two serializers</strong>: <code>buildLabContext()</code> for full context (Chat, Health Dots) and <code>buildFocusContext()</code> for slim context (Focus Card, ~200-400 tokens). The focus card only needs flagged markers and notable changes for a 40-word response.</p></li><li><p><strong>Priority-ordered sections</strong>: <code>buildLabContext()</code> outputs sections in priority order — goals and lens first, then lab values and flags, then medical context, then lifestyle cards. This exploits LLM primacy bias so the most important context gets the most attention.</p></li><li><p><strong>Data before persona</strong>: In Chat, lab context is placed before the personality layer in the system prompt. This ensures the AI processes the medical data first, then adopts the persona style.</p></li><li><p><strong>Priority-tiered system prompt</strong>: <code>CHAT_SYSTEM_PROMPT</code> uses a 4-tier structure (Core Rules → Priority Context → Lifestyle Context → Style) instead of a flat bullet list. Health goals and interpretive lens are at the top of Priority Context.</p></li><li><p><strong>Empty-card guards</strong>: Cards with no meaningful content are completely omitted rather than sent as empty sections. Each card has a specific content check (not just truthiness).</p></li><li><p><strong>Phase-aware values</strong>: For female profiles with active cycle data, estradiol, progesterone, LH, and FSH values include per-date phase labels and phase-specific reference ranges inline. Disabled for hormonal contraception and non-cycling statuses (postmenopause, pregnant, breastfeeding).</p></li><li><p><strong>Effective ranges</strong>: <code>askAIAboutMarker()</code> uses effective (phase-aware) reference ranges, not the static schema ranges. Also includes trend direction with percentage change.</p></li><li><p><strong>Robust JSON parsing</strong>: <code>loadContextHealthDots()</code> wraps the AI response JSON.parse in try-catch. On malformed responses, stale cards get gray dots while cached good data is preserved.</p></li></ol><h2 id="prompt-improvement-methodology" tabindex="-1">Prompt Improvement Methodology <a class="header-anchor" href="#prompt-improvement-methodology" aria-label="Permalink to &quot;Prompt Improvement Methodology&quot;">​</a></h2><h3 id="versioning" tabindex="-1">Versioning <a class="header-anchor" href="#versioning" aria-label="Permalink to &quot;Versioning&quot;">​</a></h3><p>Context assembly changes follow the scheme <code>YYYY-MM</code> (e.g., <code>2026-02</code>). Each version is documented in the changelog below.</p><h3 id="evaluation-criteria" tabindex="-1">Evaluation Criteria <a class="header-anchor" href="#evaluation-criteria" aria-label="Permalink to &quot;Evaluation Criteria&quot;">​</a></h3><p>When evaluating context assembly changes, assess these 5 dimensions:</p><ol><li><strong>Completeness</strong> — Does the AI receive all relevant user data? Are any fields missing from the context?</li><li><strong>Primacy positioning</strong> — Are the most important sections (goals, lens, lab values) at the top where LLMs pay most attention?</li><li><strong>Signal-to-noise</strong> — Are empty cards omitted? Is the context lean and relevant, or padded with empty sections?</li><li><strong>Specificity</strong> — Do values include proper units, reference ranges, phase context, and trend direction?</li><li><strong>Token efficiency</strong> — Is the context appropriately sized for each feature&#39;s needs? (Focus card: ~200-400 tokens, not ~8000)</li></ol><h3 id="testing-methodology" tabindex="-1">Testing Methodology <a class="header-anchor" href="#testing-methodology" aria-label="Permalink to &quot;Testing Methodology&quot;">​</a></h3><p>Changes are verified through 4 layers:</p><ol><li><strong>Source inspection</strong> — <code>test-audit.js</code> assertions read source code and verify structural properties (function existence, string patterns, section ordering)</li><li><strong>DOM verification</strong> — Browser tests check that rendered output includes expected elements</li><li><strong>Manual console check</strong> — <code>window.buildLabContext()</code> in browser console to inspect actual output</li><li><strong>Cross-feature check</strong> — Verify that Chat, Focus Card, and Health Dots all receive appropriate context</li></ol><h3 id="changelog-format" tabindex="-1">Changelog Format <a class="header-anchor" href="#changelog-format" aria-label="Permalink to &quot;Changelog Format&quot;">​</a></h3><p>Each entry documents:</p><ul><li>Version identifier (YYYY-MM)</li><li>Changes made (grouped by category)</li><li>Files modified</li><li>Rationale for non-obvious decisions</li></ul><h2 id="context-assembly-changelog" tabindex="-1">Context Assembly Changelog <a class="header-anchor" href="#context-assembly-changelog" aria-label="Permalink to &quot;Context Assembly Changelog&quot;">​</a></h2><h3 id="_2026-02-—-priority-reordering-enriched-context" tabindex="-1">2026-02 — Priority Reordering + Enriched Context <a class="header-anchor" href="#_2026-02-—-priority-reordering-enriched-context" aria-label="Permalink to &quot;2026-02 — Priority Reordering + Enriched Context&quot;">​</a></h3><p><strong>Enriched header</strong></p><ul><li>Added age (computed from DOB), current date (ISO), and unit system label to <code>buildLabContext()</code> header</li><li>Consolidated 3 inline date formatters into single <code>fmtDate</code> helper</li></ul><p><strong>Section reordering</strong> (primacy bias optimization)</p><ul><li>Health Goals → Interpretive Lens → Lab Values → Flagged Results → User Notes → Medical Conditions → Supplements → Menstrual Cycle → Diet → Exercise → Sleep → Light → Stress → Love Life → Environment → Context Notes</li><li>Rationale: AI sees &quot;what to solve&quot; first, then data, then medical context, then lifestyle</li></ul><p><strong>Empty-card guards</strong></p><ul><li>All 7 lifestyle/medical cards check for actual content (not just object truthiness)</li><li>Prevents sending <code>## Diet\\n</code> with no content when user has an empty diet card object</li></ul><p><strong>System prompt restructure</strong> (<code>CHAT_SYSTEM_PROMPT</code>)</p><ul><li>Restructured from flat 20-bullet list to 4 priority tiers (Core Rules → Priority Context → Lifestyle Context → Style)</li><li>Promoted health goals + interpretive lens to top of Priority Context</li><li>Consolidated 4 separate cortisol/HPA mentions into one cross-cutting note</li><li>Removed duplicate creatinine/urea from exercise section (already in diet)</li></ul><p><strong>Chat prompt order</strong></p><ul><li>Moved personality layer after lab data (was before): <code>SYSTEM_PROMPT + lab data + personality + search</code></li><li>Rationale: AI should process data first, then adopt persona style</li></ul><p><strong>Focus card optimization</strong> (<code>buildFocusContext</code>)</p><ul><li>New lightweight serializer: ~200-400 tokens vs ~2000-8000 from <code>buildLabContext()</code></li><li>Includes: profile (sex, age, today), major health goals, flagged markers, notable changes &gt;20%</li><li>Health-goals-aware system prompt: connects findings to goals when present</li></ul><p><strong>Per-marker AI improvements</strong> (<code>askAIAboutMarker</code>)</p><ul><li>Uses effective (phase-aware) reference ranges instead of static schema ranges</li><li>Adds trend direction with percentage change when 2+ values exist</li></ul><p><strong>PDF import fixes</strong> (<code>parseLabPDFWithAI</code>)</p><ul><li>Moved WBC differential rule from position 6 to position 3 (most error-prone extraction rule)</li><li>Added filename to user message for multi-file disambiguation</li></ul><p><strong>Robustness</strong></p><ul><li>JSON.parse try-catch guard in <code>loadContextHealthDots()</code> — malformed AI responses degrade gracefully (gray dots on stale cards, cached good data preserved)</li></ul><p><strong>Files modified</strong>: <code>js/chat.js</code>, <code>js/constants.js</code>, <code>js/views.js</code>, <code>js/context-cards.js</code>, <code>js/pdf-import.js</code>, <code>service-worker.js</code> (v50→v51), <code>test-audit.js</code>, <code>CLAUDE.md</code></p><h3 id="_2026-02b-—-staleness-signals-absent-field-awareness-gate-broadening" tabindex="-1">2026-02b — Staleness Signals + Absent Field Awareness + Gate Broadening <a class="header-anchor" href="#_2026-02b-—-staleness-signals-absent-field-awareness-gate-broadening" aria-label="Permalink to &quot;2026-02b — Staleness Signals + Absent Field Awareness + Gate Broadening&quot;">​</a></h3><p><strong>Staleness signals</strong> (<code>buildLabContext</code>)</p><ul><li><strong>Global</strong>: When most recent lab results are &gt;90 days old, inserts explicit <code>NOTE:</code> line with date and approximate months since last test</li><li><strong>Per-category</strong>: After each category&#39;s markers, if that category&#39;s latest data is &gt;90 days old, appends <code>⚠ Last tested ~N months ago</code> line — catches stale categories even when other data is recent (e.g., old fatty acids alongside fresh CBC)</li><li>System prompt instructs AI to recommend retesting stale categories and discuss what similar/changed results would suggest</li></ul><p><strong>Focus card staleness</strong> (<code>buildFocusContext</code>)</p><ul><li>Added <code>last labs &lt;date&gt;</code> to compact header so focus card can caveat stale data</li></ul><p><strong>System prompt additions</strong> (<code>CHAT_SYSTEM_PROMPT</code>)</p><ul><li>Core Rules: instruction to note when data age affects analysis relevance</li><li>Lifestyle Context: two bullets teaching AI that missing fields = user didn&#39;t provide (not assumed default), and missing sections = user hasn&#39;t filled that area</li></ul><p><strong>Auto-gating with <code>hasCardContent()</code></strong> (v53)</p><ul><li>Replaced 7 hand-written card gates with generic <code>hasCardContent(obj)</code> from <code>js/utils.js</code></li><li>Returns <code>true</code> if any field has content: strings non-empty, arrays non-empty, <code>note</code> field trimmed</li><li>Cards using auto-gate: diagnoses, diet, exercise, sleep, stress, loveLife, environment</li><li>Light &amp; Circadian keeps custom <code>lc || autoLat</code> gate (external latitude injection)</li><li>Eliminates bug class: new fields added to any card are automatically included in AI context without manual gate updates</li></ul><p><strong>Previously broadened empty-card gates</strong> (v52, now superseded by auto-gating)</p><ul><li>Diet: added <code>restrictions</code>, <code>pattern</code>, <code>snacks</code> to gate (user who only sets restrictions was silently dropped)</li><li>Exercise: added <code>intensity</code>, <code>dailyMovement</code> to gate</li><li>Sleep: added <code>schedule</code>, <code>roomTemp</code>, <code>environment</code>, <code>practices</code> to gate</li><li>Love Life: added <code>relationship</code>, <code>satisfaction</code>, <code>frequency</code>, <code>orgasm</code> to gate</li><li>Environment: added <code>climate</code>, <code>waterConcerns</code>, <code>emf</code>, <code>emfMitigation</code>, <code>homeLight</code>, <code>toxins</code>, <code>building</code> to gate</li></ul><p><strong>Files modified</strong>: <code>js/utils.js</code>, <code>js/chat.js</code>, <code>js/constants.js</code>, <code>js/views.js</code>, <code>js/changelog.js</code>, <code>service-worker.js</code> (v52→v53), <code>test-audit.js</code>, <code>test-changelog.js</code>, <code>CLAUDE.md</code></p><h3 id="_2026-03-—-change-history" tabindex="-1">2026-03 — Change History <a class="header-anchor" href="#_2026-03-—-change-history" aria-label="Permalink to &quot;2026-03 — Change History&quot;">​</a></h3><p><strong>Context card change tracking</strong> (<code>buildLabContext</code>)</p><ul><li><code>importedData.changeHistory</code> populated by <code>recordChange()</code> in <code>context-cards.js</code> whenever a card save detects a field value change</li><li>New <code>## Context Change Timeline</code> section (17) appended to <code>buildLabContext()</code> output, showing human-readable diffs between consecutive snapshots per field</li><li>Enables temporal correlation: AI can connect a diet change on March 1 to a lab shift on March 15</li></ul><p><strong>Files modified</strong>: <code>js/state.js</code>, <code>js/profile.js</code>, <code>js/context-cards.js</code>, <code>js/cycle.js</code>, <code>js/chat.js</code>, <code>js/export.js</code>, <code>tests/test-change-history.js</code>, <code>CLAUDE.md</code></p><h3 id="_2026-03b-—-section-tags" tabindex="-1">2026-03b — Section Tags <a class="header-anchor" href="#_2026-03b-—-section-tags" aria-label="Permalink to &quot;2026-03b — Section Tags&quot;">​</a></h3><p><strong>Machine-parsable section tags</strong> (<code>buildLabContext</code>)</p><ul><li>Every section wrapped in <code>[section:name]...[/section:name]</code> tags for programmatic extraction (used by getbased-mcp, Hermes Agent, OpenClaw)</li><li>Flagged results wrapped in <code>[critical]...[/critical]</code></li><li>Lab category sections include <code>updated:date</code> attribute with last data date</li><li>New <code>[index]</code> block listing available lab category keys</li><li>No change to content within sections — tags are additive</li></ul><p><strong>Files modified</strong>: <code>js/chat.js</code>, <code>tests/test-prelab.js</code></p><h2 id="source-files" tabindex="-1">Source Files <a class="header-anchor" href="#source-files" aria-label="Permalink to &quot;Source Files&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File</th><th>Key Functions</th></tr></thead><tbody><tr><td><code>js/utils.js</code></td><td><code>hasCardContent()</code> — generic empty-card gate for context assembly</td></tr><tr><td><code>js/constants.js</code></td><td><code>CHAT_SYSTEM_PROMPT</code> — priority-tiered system prompt</td></tr><tr><td><code>js/chat.js</code></td><td><code>buildLabContext()</code> — central serializer (full context)</td></tr><tr><td><code>js/chat.js</code></td><td><code>sendChatMessage()</code> — chat prompt composition</td></tr><tr><td><code>js/chat.js</code></td><td><code>askAIAboutMarker()</code> — per-marker prompt (effective ranges + trend)</td></tr><tr><td><code>js/chat.js</code></td><td><code>generateCustomPersonality()</code> — persona generator prompt</td></tr><tr><td><code>js/views.js</code></td><td><code>buildFocusContext()</code> — lightweight focus card context (~200-400 tokens)</td></tr><tr><td><code>js/views.js</code></td><td><code>loadFocusCard()</code> — focus card prompt (health-goals-aware)</td></tr><tr><td><code>js/context-cards.js</code></td><td><code>recordChange(field)</code> — timestamps context field snapshots into <code>changeHistory</code></td></tr><tr><td><code>js/context-cards.js</code></td><td><code>loadContextHealthDots()</code> — health dots prompt (JSON.parse guarded)</td></tr><tr><td><code>js/pdf-import.js</code></td><td><code>parseLabPDFWithAI()</code> — PDF import prompt (filename included)</td></tr><tr><td><code>js/pdf-import.js</code></td><td><code>buildMarkerReference()</code> — marker schema serializer</td></tr><tr><td><code>js/api.js</code></td><td><code>callClaudeAPI()</code> — provider router</td></tr><tr><td><code>js/data.js</code></td><td><code>getActiveData()</code> — data pipeline (feeds buildLabContext)</td></tr></tbody></table>`,100)])])}const g=a(p,[["render",o]]);export{u as __pageData,g as default};
